/**
 * Constrain a number within inclusive bounds.
 * @param {number} value
 * @param {number} min
 * @param {number} max
 * @returns {number}
 * @throws {TypeError} When arguments are not numbers
 */
export function clamp(value, min, max) {
  if (typeof value !== 'number' || typeof min !== 'number' || typeof max !== 'number') {
    throw new TypeError('value, min, and max must be numbers');
  }
  return Math.min(max, Math.max(min, value));
}

/**
 * @param {number} a
 * @param {number} b
 * @returns {number}
 * @throws {TypeError} When arguments are not numbers
 */
export function minOf(a, b) {
  if (typeof a !== 'number' || typeof b !== 'number') {
    throw new TypeError('arguments must be numbers');
  }
  return Math.min(a, b);
}

/**
 * @param {number} a
 * @param {number} b
 * @returns {number}
 * @throws {TypeError} When arguments are not numbers
 */
export function maxOf(a, b) {
  if (typeof a !== 'number' || typeof b !== 'number') {
    throw new TypeError('arguments must be numbers');
  }
  return Math.max(a, b);
}
